36	
37	use minixrs_ipc::{ipc_receive, ipc_send, ipc_sendrec};
38	use minixrs_kernel_shared::Message;
39	use minixrs_kernel_shared::callnr::{
40	    SYS_VMCTL, VM_BRK, VM_MMAP, VM_MUNMAP, VM_PAGEFAULT, VMCTL_CLEAR_PAGEFAULT, VMCTL_PROT_WRITE,
41	    VMCTL_PT_MAP, VMCTL_PT_UNMAP,
