67	// (and the message helpers it alone reaches) would read as dead code.
68	#[cfg_attr(test, allow(dead_code))]
69	fn main() -> ! {
70	    let system = boot_endpoint(SYSTEM);
71	    let mut msg = Message {
72	        m_source: 0,
73	        m_type: 0,
74	        payload: [0u8; 96],
75	    };
76	    loop {
