96	/// blocked on `RTS_PAGEFAULT` (the only "kill" available until PM + signals in
97	/// Phase 4). VM cannot print from EL0, so this path is silent; the symptom is a
98	/// process that stops making progress.
99	fn handle_pagefault(system: Endpoint, faulting_e: Endpoint, far: u64) {
100	    let nr = endpoint_proc(faulting_e).get();
101	    if !region::contains(nr, far) {
102	        // SIGSEGV: unmapped access outside any region. Leave it blocked.
103	        return;
104	    }
105	
106	    let page = far & !(PAGE_SIZE - 1);
