123	    let mut m = Message {
124	        m_source: 0,
125	        m_type: SYS_VMCTL,
126	        payload: [0u8; 96],
127	    };
128	    wr_i32(&mut m, 0, VMCTL_CLEAR_PAGEFAULT);
129	    wr_i32(&mut m, 4, faulting_e);
130	    let _ = ipc_sendrec(system, &mut m);
131	}
132	
133	/// Handle a `VM_BRK` request: set the caller's program break, growing or
134	/// creating its heap region. No frames are mapped here — pages fault in lazily
135	/// and are then satisfied by [`handle_pagefault`] via the region check. Reply
136	/// to the caller (it issued a SENDREC) with `m_type = OK` and the resulting
137	/// break in payload `0..8`, or the negative error in `m_type`.
138	fn handle_brk(msg: &mut Message) {
139	    let caller_e = msg.m_source;
140	    let nr = endpoint_proc(caller_e).get();
141	    let new_break = rd_u64(msg, 0);
142	
143	    let reply_type = match region::set_brk(nr, new_break) {
144	        Ok(brk) => {
145	            wr_u64(msg, 0, brk);
146	            OK
147	        }
148	        Err(e) => e,
149	    };
