160	/// the chosen base in payload `0..8`, or the negative error in `m_type`.
161	fn handle_mmap(msg: &mut Message) {
162	    let caller_e = msg.m_source;
163	    let nr = endpoint_proc(caller_e).get();
164	    let len = rd_u64(msg, 0);
165	
166	    let reply_type = match region::mmap(nr, len) {
167	        Ok(addr) => {
168	            wr_u64(msg, 0, addr);
169	            OK
170	        }
171	        Err(e) => e,
172	    };
173	
174	    msg.m_type = reply_type;
175	    msg.m_source = 0; // kernel overwrites on delivery
