187	fn handle_munmap(system: Endpoint, msg: &mut Message) {
188	    let caller_e = msg.m_source;
189	    let nr = endpoint_proc(caller_e).get();
190	    let addr = rd_u64(msg, 0);
191	    let len = rd_u64(msg, 8);
192	
193	    let reply_type = match region::munmap(nr, addr, len) {
