208	            }
209	            OK
210	        }
211	        Err(e) => e,
212	    };
213	
214	    msg.m_type = reply_type;
215	    msg.m_source = 0; // kernel overwrites on delivery
216	    let _ = ipc_send(caller_e, msg);
217	}
218	
219	// Native-endian payload accessors, mirroring the kernel's `do_vmctl` reads.
220	fn rd_u64(m: &Message, off: usize) -> u64 {
221	    let mut b = [0u8; 8];
222	    b.copy_from_slice(&m.payload[off..off + 8]);
223	    u64::from_ne_bytes(b)
224	}
225	
226	fn wr_i32(m: &mut Message, off: usize, v: i32) {
227	    m.payload[off..off + 4].copy_from_slice(&v.to_ne_bytes());
228	}
229	
230	fn wr_u64(m: &mut Message, off: usize, v: u64) {
231	    m.payload[off..off + 8].copy_from_slice(&v.to_ne_bytes());
232	}
