3	//! Static process and privilege tables, plus the boot-image table that
4	//! drives initial population.
5	//!
6	//! Storage uses `UnsafeCell<[T; N]>` wrapped in a `Sync` newtype: slice 2.2
7	//! runs on one CPU with interrupts masked, so a `Mutex` would buy nothing
8	//! over `unsafe` accessors that document the single-threaded invariant.
9	//! Slice 2.4 (timer + preemption) will revisit this — at that point we'll
10	//! need a per-table lock or a percpu pattern, not before.
11	
12	use core::cell::UnsafeCell;
13	
14	use minixrs_kernel_shared::callnr::NR_KERN_CALLS_PHASE3;
15	use minixrs_kernel_shared::com::{
16	    ASYNCM, CLOCK, DS_PROC_NR, HARDWARE, IDLE, INIT_PROC_NR, MEM_PROC_NR, MFS_PROC_NR,
17	    NR_BOOT_PROCS, NR_PROCS, NR_SYS_PROCS, NR_TASKS, PFS_PROC_NR, PM_PROC_NR, RS_PROC_NR,
18	    SCHED_PROC_NR, SYSTEM, TTY_PROC_NR, VFS_PROC_NR, VM_PROC_NR, boot_endpoint,
19	};
20	use minixrs_kernel_shared::{PrivId, ProcNr};
21	
22	use super::flags::{
23	    BILLABLE, CSK_T, PREEMPTIBLE, ROOT_SYS_PROC, RTS_NO_PRIV, SRV_T, SYS_PROC, TSK_T, VM_SYS_PROC,
24	};
25	use super::priv_struct::{IPC_MAP_CHUNKS, K_CALL_MASK_CHUNKS, Priv};
26	use super::proc_struct::{PROC_NAME_LEN, Proc};
27	
28	/// Total slots in the process table: kernel tasks plus user-process room.
29	pub const N_PROC_SLOTS: usize = NR_TASKS + NR_PROCS;
30	
31	// ---------------------------------------------------------------------------
32	// Scheduling constants (slice 2.4 expands these into full bands).
33	// ---------------------------------------------------------------------------
34	
35	/// Highest scheduler priority — reserved for kernel tasks.
36	pub const TASK_Q: u8 = 0;
37	/// Default priority for the root system process (RS).
38	pub const RS_Q: u8 = 4;
39	/// Default priority for the VM server.
40	pub const VM_Q: u8 = 4;
41	/// Default priority for ordinary boot servers.
42	pub const SRV_Q: u8 = 8;
43	/// Default priority for `init`.
44	pub const INIT_Q: u8 = 8;
45	/// Lowest priority — the idle task only.
46	pub const IDLE_Q: u8 = 15;
47	
48	/// Default scheduling quantum for user-class servers (ms).
49	pub const SRV_QUANTUM_MS: u32 = 200;
50	
51	// ---------------------------------------------------------------------------
52	// Static storage.
53	// ---------------------------------------------------------------------------
54	
55	#[repr(transparent)]
56	struct ProcStorage(UnsafeCell<[Proc; N_PROC_SLOTS]>);
57	// SAFETY: slice 2.2 runs single-threaded with interrupts masked; concurrent
58	// access to PROC_TABLE is impossible. Future slices that enable preemption
59	// must wrap this in a proper lock before keeping this `unsafe impl`.
60	unsafe impl Sync for ProcStorage {}
61	
62	#[repr(transparent)]
63	struct PrivStorage(UnsafeCell<[Priv; NR_SYS_PROCS]>);
64	// SAFETY: same single-threaded invariant as ProcStorage.
65	unsafe impl Sync for PrivStorage {}
66	
67	static PROC_TABLE: ProcStorage =
68	    ProcStorage(UnsafeCell::new([const { Proc::EMPTY }; N_PROC_SLOTS]));
69	static PRIV_TABLE: PrivStorage =
70	    PrivStorage(UnsafeCell::new([const { Priv::EMPTY }; NR_SYS_PROCS]));
71	
72	/// Map a [`ProcNr`] to its index in the process table.
73	///
74	/// Kernel tasks (negative `nr`) land in slots `[0, NR_TASKS)`; user processes
75	/// land in `[NR_TASKS, N_PROC_SLOTS)`. Returns `None` if `nr` is outside the
76	/// allocated range.
77	pub const fn proc_index(nr: ProcNr) -> Option<usize> {
78	    let n = nr.get();
79	    let shifted = n + NR_TASKS as i32;
80	    if shifted < 0 || (shifted as usize) >= N_PROC_SLOTS {
81	        None
82	    } else {
83	        Some(shifted as usize)
84	    }
85	}
86	
87	/// Map a [`PrivId`] to its index in the privilege table.
88	pub const fn priv_index(id: PrivId) -> Option<usize> {
89	    let n = id.as_usize();
90	    if n >= NR_SYS_PROCS { None } else { Some(n) }
91	}
92	
93	// ---------------------------------------------------------------------------
94	// Boot image.
95	// ---------------------------------------------------------------------------
96	
97	struct BootEntry {
98	    nr: ProcNr,
99	    name: &'static [u8],
100	    priv_flags: u16,
101	    trap_mask: u16,
102	    priority: u8,
103	    quantum_ms: u32,
104	    runnable: bool,
105	}
106	
107	const N_IMAGE: usize = NR_TASKS + NR_BOOT_PROCS;
108	const _: () = assert!(N_IMAGE == 16);
109	
110	static IMAGE: [BootEntry; N_IMAGE] = [
