174	        runnable: false,
175	    },
176	    BootEntry {
177	        nr: RS_PROC_NR,
178	        name: b"rs",
179	        priv_flags: SYS_PROC | PREEMPTIBLE | ROOT_SYS_PROC,
180	        trap_mask: SRV_T,
181	        priority: RS_Q,
182	        quantum_ms: SRV_QUANTUM_MS,
183	        runnable: false,
184	    },
185	    BootEntry {
186	        nr: MEM_PROC_NR,
187	        name: b"memory",
188	        priv_flags: SYS_PROC | PREEMPTIBLE,
189	        trap_mask: SRV_T,
