237	        runnable: false,
238	    },
239	    BootEntry {
240	        nr: SCHED_PROC_NR,
241	        name: b"sched",
242	        priv_flags: SYS_PROC | PREEMPTIBLE,
243	        trap_mask: SRV_T,
244	        priority: SRV_Q,
245	        quantum_ms: SRV_QUANTUM_MS,
246	        runnable: false,
247	    },
248	    BootEntry {
249	        nr: INIT_PROC_NR,
250	        name: b"init",
251	        priv_flags: SYS_PROC | PREEMPTIBLE,
252	        trap_mask: SRV_T,
253	        priority: INIT_Q,
254	        quantum_ms: SRV_QUANTUM_MS,
255	        runnable: false,
256	    },
257	];
258	
259	// ---------------------------------------------------------------------------
260	// Access helpers. All return raw pointers — callers carry the single-threaded
261	// invariant.
262	// ---------------------------------------------------------------------------
263	
264	/// SAFETY: caller must ensure no other reference into `PROC_TABLE` exists.
265	pub(crate) unsafe fn proc_slot_mut(nr: ProcNr) -> Option<&'static mut Proc> {
266	    let idx = proc_index(nr)?;
267	    // SAFETY: `idx` is in-range; single-threaded boot context.
268	    let arr = unsafe { &mut *PROC_TABLE.0.get() };
269	    Some(&mut arr[idx])
270	}
271	
272	/// SAFETY: caller must ensure no exclusive reference into `PROC_TABLE` exists.
273	pub(crate) unsafe fn proc_table_ref() -> &'static [Proc; N_PROC_SLOTS] {
274	    // SAFETY: single-threaded boot context.
275	    unsafe { &*PROC_TABLE.0.get() }
276	}
277	
278	/// Borrow `PROC_TABLE` mutably as a slice. Used by `ipc::do_ipc` to hand a
279	/// single `&mut [Proc]` down through every IPC primitive — avoiding the
280	/// two-`&mut`-from-one-`UnsafeCell` hazard that arises if each primitive
281	/// re-borrows individual slots via `proc_slot_mut`.
282	///
283	/// SAFETY: caller must hold the single-threaded-boot / IRQ-masked
284	/// invariant and must not hold any other reference into `PROC_TABLE`
285	/// while the returned borrow is live.
286	pub(crate) unsafe fn proc_table_mut_slice() -> &'static mut [Proc; N_PROC_SLOTS] {
287	    // SAFETY: forwarded — caller's invariants.
288	    unsafe { &mut *PROC_TABLE.0.get() }
289	}
290	
291	/// SAFETY: caller must ensure no other reference into `PRIV_TABLE` exists.
292	pub(crate) unsafe fn priv_slot_mut(id: PrivId) -> Option<&'static mut Priv> {
293	    let idx = priv_index(id)?;
294	    // SAFETY: `idx` is in-range; single-threaded boot context.
295	    let arr = unsafe { &mut *PRIV_TABLE.0.get() };
296	    Some(&mut arr[idx])
297	}
298	
299	/// SAFETY: caller must ensure no exclusive reference into `PRIV_TABLE` exists.
300	pub(crate) unsafe fn priv_table_ref() -> &'static [Priv; NR_SYS_PROCS] {
301	    // SAFETY: single-threaded boot context.
302	    unsafe { &*PRIV_TABLE.0.get() }
303	}
304	
305	/// Borrow `PRIV_TABLE` mutably as a slice. Companion of
306	/// [`proc_table_mut_slice`] — `ipc::do_ipc` materializes both at once and
307	/// passes them down to the per-primitive handlers.
308	///
309	/// SAFETY: caller must hold the single-threaded-boot / IRQ-masked
310	/// invariant and must not hold any other reference into `PRIV_TABLE`
311	/// while the returned borrow is live.
312	pub(crate) unsafe fn priv_table_mut_slice() -> &'static mut [Priv; NR_SYS_PROCS] {
313	    // SAFETY: forwarded — caller's invariants.
314	    unsafe { &mut *PRIV_TABLE.0.get() }
315	}
316	
317	// ---------------------------------------------------------------------------
318	// Boot-time population.
319	// ---------------------------------------------------------------------------
320	
321	/// Populate `PROC_TABLE` and `PRIV_TABLE` from `IMAGE`.
322	///
323	/// Called exactly once from `kmain` during boot. Slice 2.4's scheduler will
324	/// assume one-shot init; double-calling would clobber any RTS bits the
325	/// scheduler has set since.
326	pub fn init() {
327	    init_empty_slots();
328	    init_boot_image();
329	}
330	
331	fn init_empty_slots() {
332	    // Give every slot a valid (nr, endpoint) so that index-based traversal
333	    // never sees a stale zero `nr` after `Proc::EMPTY` initialization.
334	    for i in 0..N_PROC_SLOTS {
335	        let nr = ProcNr::new(i as i32 - NR_TASKS as i32);
336	        // SAFETY: index in-range; single-threaded boot context; no other
337	        // references into PROC_TABLE exist at this point in `init`.
338	        let p = unsafe { proc_slot_mut(nr) }.expect("proc index in range");
339	        p.nr = nr;
340	        p.endpoint = boot_endpoint(nr);
341	        // EMPTY left rts_flags = RTS_SLOT_FREE — leave it that way.
342	    }
343	
344	    for i in 0..NR_SYS_PROCS {
345	        // SAFETY: index in-range; single-threaded boot context.
346	        let pr = unsafe { priv_slot_mut(PrivId::new(i as u16)) }.expect("priv index in range");
347	        pr.id = PrivId::new(i as u16);
348	    }
349	}
350	
351	fn init_boot_image() {
352	    // Active priv-slot count after population — the IPC bitmap for SRV_T
353	    // entries needs to enumerate every active slot.
354	    let n_active = N_IMAGE as u16;
355	
356	    for (slot, entry) in IMAGE.iter().enumerate() {
357	        let priv_id = PrivId::new(slot as u16);
358	        populate_priv(priv_id, entry, n_active);
359	        populate_proc(priv_id, entry);
360	    }
361	}
362	
363	fn populate_priv(id: PrivId, entry: &BootEntry, n_active: u16) {
364	    // SAFETY: priv index < NR_SYS_PROCS; single-threaded boot context; no
365	    // overlapping reference into PRIV_TABLE held across the call.
366	    let pr = unsafe { priv_slot_mut(id) }.expect("priv slot in range");
367	    pr.id = id;
368	    pr.proc_nr = Some(entry.nr);
369	    pr.flags = entry.priv_flags;
370	    pr.trap_mask = entry.trap_mask;
371	
372	    if entry.trap_mask == SRV_T {
373	        // SRV_T privs can send to every active slot. Set bits [0, n_active).
374	        fill_bits(&mut pr.ipc_to, n_active as usize);
375	        // SRV_T privs can issue every kernel call defined so far.
376	        // TODO(slice 2.6): widen as new kernel calls land — this bound must
377	        // track the highest `SYS_*` number, not the Phase-2 count.
378	        fill_bits(&mut pr.k_call_mask, NR_KERN_CALLS_PHASE3);
379	    }
380	    // Kernel-task slots leave ipc_to and k_call_mask zeroed.
381	
382	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
383	    pr.notify_pending.fill(0);
384	    pr.asyn_pending.fill(0);
385	}
386	
387	fn populate_proc(priv_id: PrivId, entry: &BootEntry) {
388	    // SAFETY: proc index in-range; single-threaded boot context; no
389	    // overlapping reference into PROC_TABLE held across the call.
390	    let p = unsafe { proc_slot_mut(entry.nr) }.expect("proc slot in range");
391	    p.priv_id = Some(priv_id);
392	    p.priority = entry.priority;
393	    p.quantum_ms = entry.quantum_ms;
394	    p.quantum_left = entry.quantum_ms as u64;
395	    p.endpoint = boot_endpoint(entry.nr);
396	    p.nr = entry.nr;
397	
398	    // Copy name into the fixed-width field (truncates silently at PROC_NAME_LEN).
399	    let n = core::cmp::min(entry.name.len(), PROC_NAME_LEN - 1);
400	    p.name[..n].copy_from_slice(&entry.name[..n]);
401	    p.name[n..].fill(0);
402	
403	    let rts = if entry.runnable { 0 } else { RTS_NO_PRIV };
404	    p.rts_flags
405	        .store(rts, core::sync::atomic::Ordering::Relaxed);
406	}
407	
408	/// Set the lowest `n` bits in a `u32` bitmap.
409	fn fill_bits(map: &mut [u32], n: usize) {
410	    for i in 0..n {
411	        let word = i / 32;
412	        let bit = i % 32;
413	        if word < map.len() {
414	            map[word] |= 1 << bit;
415	        }
416	    }
417	}
418	
419	// Compile-time sanity that the bitmap sizing came out as expected.
420	const _: () = assert!(IPC_MAP_CHUNKS == 2);
421	const _: () = assert!(K_CALL_MASK_CHUNKS == 1);
422	
423	/// Number of slots in `PROC_TABLE` (for the dump helper).
424	pub const fn n_proc_slots() -> usize {
425	    N_PROC_SLOTS
426	}
427	
428	/// Number of slots in `IMAGE` (for the dump helper).
429	pub const fn n_image_slots() -> usize {
430	    N_IMAGE
431	}
